?>"></label><label class="full">Extrait<textarea name="excerpt"><?= e($article['excerpt']) ?></textarea></label><label>SEO title<input name="seo_title" value="<?= e($article['seo_title']) ?>"></label><label>SEO description<textarea name="seo_description"><?= e($article['seo_description']) ?></textarea></label><label class="full">Contenu<textarea name="content" style="min-height:420px"><?= e($article['content']) ?></textarea></label></div></form><?php admin_footer(); ?>
